def to_twos_complement(number, bits=8):
    """Convert a signed integer to two's complement binary"""
    if number >= 0:
        return format(number, f'0{bits}b')
    else:
        # For negative: 2^bits + number (handles wrap-around)
        positive_rep = (2 ** bits) + number
        return format(positive_rep, f'0{bits}b')

def from_twos_complement(binary_str, bits=8):
    """Convert two's complement binary to signed integer"""
    if not binary_str.startswith('0b'):
        binary_str = '0b' + binary_str

    value = int(binary_str, 2)

    # If MSB is 1, it's negative - subtract 2^bits
    if value >= 2 ** (bits - 1):
        value = value - (2 ** bits)

    return value

def twos_complement_range(bits):
    """Calculate min and max values for n-bit two's complement"""
    min_val = -(2 ** (bits - 1))
    max_val = (2 ** (bits - 1)) - 1
    return min_val, max_val

# Display ranges
print("Two's Complement Range:")
for bits in [4, 8, 16, 32]:
    min_v, max_v = twos_complement_range(bits)
    print(f"{bits}-bit: {min_v} to {max_v}")

# Convert positive and negative numbers
print("\nConvert to Two's Complement (8-bit):")
for num in [1, 42, -1, -42, -128]:
    tc = to_twos_complement(num, 8)
    print(f"{num:4d} -> {tc}")

# Convert back from two's complement
print("\nConvert from Two's Complement (8-bit):")
test_cases = ['00000001', '00101010', '11111111', '11010110', '10000000']
for binary in test_cases:
    decimal = from_twos_complement(binary, 8)
    print(f"{binary} -> {decimal:4d}")
